var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님, 제가 돌아왔습니다.","JPN":"救世主様、ただいま戻りました。","ENG":"I have returned, Savior.","TWN":"我回來了，救贖者大人。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"발키리는 예정대로 차원의 미로를 헤매게 되었답니다.","JPN":"ヴァルキリーは予定通り、次元の迷路に閉じ込めました。","ENG":"Valkyrie is now lost in the maze of dimensions, as planned.","TWN":"女武神如我們計畫的那般迷失在次元迷宮裡了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"더는 저희에게 위협이 되지 않겠지요.","JPN":"これ以上私たちの脅威にはならないでしょう。","ENG":"She shall no longer be a threat to us.","TWN":"她已經不再是個威脅。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이제 겁없이 성역에 발을 들인 늑대를 처리하시기만 하면……","JPN":"あとは身の程も知らず聖域に足を踏み入れた狼を始末すれば……","ENG":"Now, all that is left is to slay the brazen Wolf who entered the sanctuary–","TWN":"現在只要再解決掉膽敢踏足聖域的狼……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"내숭은 그만둬. 사령술사.","JPN":"猫を被るのはやめろ。降霊術師。","ENG":"Drop the act, Necromancer.","TWN":"別裝了，死靈術師。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 찾는 구원자는 여기 없어.","JPN":"その救世主はここにいない。","ENG":"Your dear Savior isn't here.","TWN":"你的救贖者不在這裡。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은……. 이방인의 호위로군요.","JPN":"あなたは……異邦人の護衛。","ENG":"You... You must be the outsider's bodyguard.","TWN":"你是……外邦人的護衛。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"다음부터는 미리 기척을 내 주시지요.","JPN":"次からは居るなら居ると言ってください。","ENG":"I kindly ask you to reveal your presence next time.","TWN":"拜託你下次提前給個動靜。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"시궁창의 쥐처럼 숨어 있다 나타나시면, 놀라서 저도 모르게 죽여 버릴지 모르니까요.","JPN":"ドブネズミのように見えないところから急に出てこられたら、驚いて思わず殺してしまうかもしれませんから。","ENG":"Should you continue to hide yourself like some vermin in the sewers, I might kill you by accident.","TWN":"像躲在臭水溝裡的老鼠一樣突然出現，沒有失手殺了你已經很不錯了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그건 어릴 적 경험에서 우러나온 비유인가?","JPN":"それは子どもの頃の経験から言っているのか？","ENG":"Speaking from past experiences, huh?","TWN":"這個比喻是源於你的童年經歷嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……함부로 남의 속내를 엿보지 마세요.","JPN":"……勝手に人の心の中を覗かないでください。","ENG":"...Please do not read other people without their consent.","TWN":"……隨意窺探別人內心是不禮貌的行為。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신들 중에 존중 받을 만한 자는 이 세계의 대적자뿐이란 걸 모르진 않으실 텐데요.","JPN":"あなた方の中で尊重に値するのは、この世界の敵対者のみであることをお忘れなく。","ENG":"Surely you are aware that the Antagonist is the only one worth our courtesy.","TWN":"你們中唯一值得尊重的人就是這個世界的敵對者了，你應該不會不知道吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"과연 그 자가 당신의 실언까지 대신 책임지려고 나설까요?","JPN":"その方があなたの失言まで庇ってくれればいいですけどね。","ENG":"I doubt he would be willing to take responsibility for your wrongdoings.","TWN":"他真會願意出面替你的失言負責？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"감추고 싶어하는 구석을 들췄다면 미안하게 됐어. 가끔 멋대로 이러거든.","JPN":"隠しておきたいことだったなら、悪かったな。つい口が滑った。","ENG":"My apologies if I brought up something you wanted to hide. I can't help it sometimes.","TWN":"如果恰好揭露了你的舊傷疤，那我很抱歉。有時候我是會控制不住這個能力。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신의 사과 따위 필요없습니다. 그러니 묻는 말에나 대답하시죠.","JPN":"あなたに謝罪など求めていません。ですから質問にだけ答えてください。","ENG":"I do not need your apology. What I need is an answer to my question.","TWN":"我不需要你的道歉。所以，請回答我的問題。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자께서는 어디로 가셨습니까? 대적자는요?","JPN":"救世主様はどちらへ？　敵対者は？","ENG":"Where did the Savior head to? And the Antagonist?","TWN":"救贖者大人去哪兒了？還有敵對者呢？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"두 사람 다 행선지는 밝히지 않았어.","JPN":"二人とも行先は言っていなかった。","ENG":"Neither of them said where they were going.","TWN":"他們沒有透露目的地。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"하지만 구원자의 용건은 알아. 늑대를 마중 나간다고 하더군.","JPN":"でも、救世主が何をしに行ったかは知っている。狼を迎えに行くと言っていた。","ENG":"But I know what the Savior's up to. Said he's going to go \\"greet\\" the Wolf.","TWN":"不過我知道救贖者的事。他大概是去和狼打招呼了吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"늑대를? 구원자님께서?","JPN":"狼？　救世主様が？","ENG":"The Wolf? Greeted by the Savior himself?","TWN":"狼？救贖者大人要去親自迎接？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 말을 듣고도 혼자 가시게 놔뒀다는 건가요, 지금?","JPN":"あなたはそれを聞いておきながら、お一人で行かれるのを止めなかったのですか？","ENG":"Are you saying that you let him go, knowing what he was getting into?","TWN":"那你還讓他一個人離開？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"나는 칼잡이야. 보육사로 고용된 적은 없을 텐데.","JPN":"私は剣士だ。保育係として雇われた覚えはない。","ENG":"I am a swordsman, not a nanny.","TWN":"我是拿刀的人，不是被雇來看孩子的保姆。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Krrrgh!","TWN":"……哼！"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어딜 가려고?","JPN":"どこへ行く？","ENG":"Going somewhere?","TWN":"你要去哪裡？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님을 모시고 돌아올 겁니다.","JPN":"救世主様をお迎えに行きます。","ENG":"I will be back with the Savior.","TWN":"我會去接救贖者大人回來。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 분께서는 클리포트 게임을 선언한 것으로 소임을 다하셨어요.","JPN":"あの方はクリフォトゲームを宣言したことで、もうお役目は果たされました。","ENG":"He has served his duty by declaring the Qliphoth Game.","TWN":"宣告逆卡巴拉遊戲的責任已經盡到了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"남은 건 저희가 사로잡은 늑대의 목을 치는 최후의 의식뿐.","JPN":"残るは私たちが捕らえた狼の首を討つ最後の儀式のみ。","ENG":"What remains is merely the killing of the Wolf that we have captured.","TWN":"如今只剩下最後的這個儀式……砍下狼的腦袋。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"몸소 사냥에 나서실 이유는 존재하지 않습니다.","JPN":"あの方が直接狩りに出るような理由はどこにもありません。","ENG":"There is no need for him to partake in battle anymore.","TWN":"他沒理由親自屈尊下場。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그 상태로?","JPN":"その状態で？","ENG":"In that state?","TWN":"憑你如今的狀態嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"Pardon?","TWN":"什麼意思？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"재능도 없이 지팡이에 의존하는 주제에 너무 무리했어.","JPN":"才能もなく杖だけに頼っているくせに、無理のしすぎだ。","ENG":"You, only relying on that staff without any talent, have pushed yourself too hard.","TWN":"你沒有才能，對權杖的依仗也太重，這太勉強了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"사령술이 아무리 유용해도 사람들이 기피하는 건 후환을 두려워해서야.","JPN":"降霊術のような便利なものを人々が忌避するのは、それだけ恐ろしい副作用があるからだ。","ENG":"You know the reason why people avoid necromancy? They’re scared of what comes afterwards.","TWN":"不管死靈術多麼有用，人們都會忌諱它帶來的後患。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"순환을 어그러뜨린 대가지.","JPN":"世の理に反した代償としてね。","ENG":"There’s a price to pay for going against the cycle of life.","TWN":"那是打破迴圈的代價。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하…….","JPN":"はぁ……","ENG":"Ha...","TWN":"哈……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"걱정해 줘서 고맙지만, 그런 쓸데없는 충고는 예전부터 많이 들었답니다.","JPN":"ご心配はありがたいのですが、あいにくそのようなくだらない忠告は聞き飽きているんです。","ENG":"As much as I appreciate your concern, this is not my first time hearing that useless piece of advice.","TWN":"多謝擔心，不過這種沒用的忠告我以前就經常聽到。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 제가 돌아오기 전까지, 그 더러운 눈은 뽑아 버리는 편이 나을 거예요.","JPN":"ですから私が戻るまでに、その汚い眼球はえぐり取っておいてくださいね。","ENG":"So why don't you go ahead and pull out that wretched eye of yours before I come back?","TWN":"所以在我回來之前，你那雙可憐的眼睛還是自己挖掉比較好。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"굳이 제 손에 피를 묻히고 싶지는 않거든요.","JPN":"自分の手を血で汚したくはないので。","ENG":"I wouldn't want to go through the trouble of getting blood all over my hands.","TWN":"因為我不想讓我的雙手沾上鮮血。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"……나도 굳이 내 손에 피를 묻힐 일 없었으면 좋겠어.","JPN":"……私も自分の手を血で染めることは遠慮したいものだ。","ENG":"...Same here. I wouldn't want any blood on my hands.","TWN":"……我也不希望自己的雙手沾上鮮血。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그것도 네가 돌아왔을 때의 이야기겠지만. 아가.","JPN":"それもお前が戻ってこられたらの話だが。","ENG":"That is... if you make it back alive, kid.","TWN":"不過這也要等到你回來再說了，孩子。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};